var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"죽음을 넘어선 용기, 그리고 애국심.","JPN":"死を乗り越えた勇気、そして愛国心。","ENG":"Courage and patriotism beyond death.","TWN":"戰勝死亡的勇氣，還有愛國心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"명예를 버리고 대의를 위해 희생한 도미닉 킹 레지날드 소장의 정신은 우리의 군과 나라에서 영원히 기려져야 할 것입니다.","JPN":"名誉を捨て、大義のために犠牲になったドミニーク・キング・レジナルド少将の精神を、我ら軍と国が永遠に称えるべきです。","ENG":"Major General Dominic King Reginald sacrificed his honor for the greater good. Our military and nation must eternally remember this great man.","TWN":"捨棄名譽，為了大義而犧牲的多明尼克·金·雷吉納德少將，我們軍人和國家將永遠紀念他的精神。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"레지날드 준장이 종적을 감춘 동안 리플레이서에 침투해서 기밀 공작을 수행했다고?","JPN":"レジナルド少将が姿を消してる間、リプレイサーに侵入して機密工作を行ったって？","ENG":"So they're saying BG Reginald had been working undercover at the Replacer Syndicate?","TWN":"雷吉納德準將銷聲匿跡這段時間，是為執行機密行動，潛入了克隆集團？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하여튼 웃기지도 않아, 정말.","JPN":"笑いもんじゃない、まったく。","ENG":"That's a whole another level of ridiculous.","TWN":"真是一點都不好笑。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"악의 조직 보스를 이런 식으로 미화하는 법이 어디 있어?","JPN":"悪の組織のボスをこんなふうに美化してどうするのよ！","ENG":"How could they euphemize the boss of an evil organization like this?","TWN":"哪有這樣洗白邪惡組織老大的啊？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 킹의 정체는 기밀 사항이니까요.","JPN":"リプレイサー・キングの正体は機密事項ですから。","ENG":"The Replacer King's identity is top secret.","TWN":"畢竟克隆·帝皇的真實身份是機密。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"상부에서도 어쩔 수 없는 결정이었을 겁니다. 언동에 주의해 주십시오.","JPN":"上層部も他に方法がなかったと思います。言動に注意してください。","ENG":"I'm sure the leadership didn't have much choice. Please exercise a little more discretion in what you say.","TWN":"上級也是無可奈何。請注意自己的言辭。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그거 안타깝게 됐네.","JPN":"それは残念。","ENG":"Well, that's too bad.","TWN":"那可真是遺憾。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"원래 해커는 꽁꽁 감출수록 더 까발리고 싶어지는 불치병에 걸려 있거든?","JPN":"元々ハッカーっていうのは、隠せば隠すほど暴きたくなる難病にかかっているのよ。","ENG":"Hackers get this insatiable desire to expose things the harder folks try to hide them!","TWN":"隱藏得越深就越想去揭開，這才是駭客喔？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨!","JPN":"シルビアさん！","ENG":"Sylvia!","TWN":"希爾維亞小姐！"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......저도 실비아와 같은 생각입니다.","JPN":"……俺もシルビアと同じ考えです。","ENG":"I actually agree with Sylvia.","TWN":"……我和希爾維亞想得一樣。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"세상을 멸망시키려고 했던 작자에게 이런 의전을 갖춰 준다니......","JPN":"世界を滅ぼそうとした奴を、国際儀礼に則ってもてなすなんて……","ENG":"They're honoring a villain who almost brought an end to this world...","TWN":"那傢伙可是曾經想毀滅世界啊，竟然為他準備這樣的儀式……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"납득하기가 어렵군요.","JPN":"納得いきません。","ENG":"I find it quite difficult to accept.","TWN":"我無法接受。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"섭섭하겠지만 카일 말에도 일리가 있어.","JPN":"残念ながら、カイル少佐の言うことにも一理ある。","ENG":"I understand your disappointment, but Kyle's got a point.","TWN":"雖然有些令人難過，但凱爾說的確實有理。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉의 행적이 세상에 알려지면 간신히 유지되던 질서와 신뢰가 모두 붕괴될 거야.","JPN":"ドミニークの行方が世間に知られたら、辛うじて保たれていた秩序や信頼が崩れてしまうだろう。","ENG":"If his true actions are revealed to the public, any semblance of order and trust that has been maintained in the world will collapse.","TWN":"如果多明尼克的事蹟被世人知曉，那麼一直以來勉強維持的秩序與信任全部都會崩壞。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대정화 전쟁의 참전자가 멸망을 두려워해서 그런 짓을 저질렀다......","JPN":"大浄化戦争の参戦者が、滅亡を恐れてあんなことを犯した……","ENG":"Imagine if they heard how a veteran of the Grand Purification War did that out of his fear of extinction...","TWN":"身為大淨化戰爭的參戰者，居然會因為害怕滅亡做出那種事……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이면세계는 이제 태스크포스가 알아서 할 거라고 믿던 사람들이, 어떻게 반응하겠나?","JPN":"裏世界はもうタスクフォースがなんとかしてくれると信じていた人々がどう反応すると思う？","ENG":"How would people react? Especially when they thought the TASKFORCEs would take care of all things Counterside?","TWN":"那些認為特遣勢力可以處理好異界問題的人，知道了會有什麼反應呢？"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"전쟁으로부터 겨우 20년밖에 지나지 않았어.","JPN":"戦争からたった20年しか経っていない。","ENG":"It's been only 20 years since the war.","TWN":"戰爭結束才僅僅過去了20年。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이 이상 사회에 부담을 줄 필요는 없겠지.","JPN":"これ以上社会に負担をかける必要はないだろう。","ENG":"We don't need to put any greater strain on society than we already have.","TWN":"沒必要再給社會增加負擔了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……そうですか。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 먼저 돌아가게, 난 잠시 할 일이 생겨서 이만.","JPN":"さて、私は先に帰る。ちょっと用事を思い出してな。","ENG":"Why don't you guys go ahead without me? I've got an errand to run.","TWN":"我還有些事情要做，就先告辭了。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"알겠습니다. 사령부에서 뵙도록 하겠습니다.","JPN":"わかりました。では後ほど司令部で。","ENG":"Understood. We'll see you back at HQ.","TWN":"知道了，我們司令部再見吧。"},"stage":{"bg":"TOMB","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"레지날드 준장께서 세상을 구한 기밀 공작원이었다니......","JPN":"レジナルド少将が世界を救った機密工作員だったとは……","ENG":"Who knew BG Reginald was an undercover agent who saved the world?","TWN":"竟然是從雷吉納德準將手中拯救了世界的秘密特務……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"저도 모르는 사실이었는데 리플레이서 잔당들이 들으면 깜짝 놀라겠군요, 하하.","JPN":"僕も知らない事実でしたが､リプレイサーの残党が聞いたらびっくりするでしょうね､はは｡","ENG":"I certainly had no idea. I bet those remaining Replacers would jump out of their socks. Hah hah.","TWN":"這事情連我都不知道，要是克隆集團的殘黨聽到會有多驚訝啊，哈哈。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......역시 자네였군.","JPN":"……やはり君だったのか｡","ENG":"So it really was you.","TWN":"……果然是你啊。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"오랜만입니다, 소장님, 아니 이젠 중장님이시죠.","JPN":"お久しぶりです、少将。いや、今は中将ですね。","ENG":"Long time no see, Major General. Or is it Lieutenant General now?","TWN":"好久不見，少將，不，現在已經是中將了吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뉴 오하이오 탈취작전 이후로 처음 뵙는군요.","JPN":"ニューオハイオ奪取作戦以来、初めてお会いします。","ENG":"I haven't seen you since the New Ohio heist.","TWN":"這是我們自新俄亥俄奪取戰以來第一次見面吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"알고 있겠지만 자네가 내게 별로 반가운 얼굴은 아니야.","JPN":"知っていると思うが、私にとって君は会えて嬉しい存在ではない。","ENG":"As you may know, I'm not very glad to see you.","TWN":"你不歡迎我的想法全都寫在臉上了。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아의 보고서에서 자네 이야기가 나왔을 때는 심장이 멎을 뻔 했지.","JPN":"シルビアの報告書で君の話が出てきた時は、心臓が止まるかと思ったよ。","ENG":"My heart skipped a beat when I read about you in Sylvia's report.","TWN":"希爾維亞的報告書裡提到你時，我心臟差點就就停了。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서에게도 협력하고 있던 걸 보면...... 역시 도미닉의 일탈을 부추긴 것도 자네의 짓이겠지?","JPN":"リプレイサーにも協力していたのを見る限り……やはりドミニークの逸脱をそそのかしたのも君の仕業だろう？","ENG":"Seeing as how you'd been collaborating with the Replacers... You're the one who encouraged Dominic's deviance, aren't you?","TWN":"既然你也在和克隆集團合作……煽動多明尼克離職的罪魁禍首果然也是你吧？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"글쎄요. 저는 오래 된 자료 몇 점을 전달해 드린 것뿐이라서요.","JPN":"さあ、どうでしょう。僕は古い資料をいくつか渡しただけです。","ENG":"Beats me. All I did was pass on a few bits of old information.","TWN":"不知道耶，畢竟我只是傳給他幾份舊資料而已。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"결국 결정을 내리는 건 본인의 몫이죠, 그렇지 않나요?","JPN":"結局のところすべては自分次第です。そうじゃないですか？","ENG":"It's really up to oneself to decided what you want to do, wouldn't you agree?","TWN":"做出最終決定的不是他本人嗎？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 너무 그렇게 노려보지 마세요. 무서우니까요.","JPN":"はは、そんなに睨まないでください。怖いですから。","ENG":"Hah hah, please don't glare at me like that. It's scary.","TWN":"哈哈，請不要這樣瞪我嘛，很可怕耶。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이곳이 민간인 거주지라는 걸 감사하게 여기게.","JPN":"ここが民間人の居住地だということに感謝するんだな。","ENG":"You should be grateful that this is a civilian residential neighborhood.","TWN":"你最好慶幸這裡是平民的居住地。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않으면 가만두지 않았을 테니까.","JPN":"そうでなかったら、痛い目にあってただろう。","ENG":"Otherwise, I'd do a lot more than glaring.","TWN":"不然我是不會輕易放過你的。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서...... 여기서 만나자고 한 이유가 뭐지?","JPN":"それで……ここで会おうとした理由は何だ？","ENG":"So... Why did you ask to meet here?","TWN":"所以……你約我在這裡見面的理由是什麼？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"별거 아닙니다. 그저 전해드릴 자료가 있어서요.","JPN":"大したことではありません。お渡ししたい資料がありまして。","ENG":"Nothing special, really. I just have some data I have to pass on to you.","TWN":"也不是什麼大事。只是有份資料要交給妳。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이건...... 메모리 카드?","JPN":"これは……メモリーカード？","ENG":"What's this? A memory card?","TWN":"這……記憶卡？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 안에는 뉴 오하이오가 파괴되기 전에 백업해둔 데이터가 들어 있죠.","JPN":"その中には、ニューオハイオが破壊される前にバックアップしておいたデータが入っています。","ENG":"That contains the data backed up from the New Ohio before it was destroyed.","TWN":"裡面有新俄亥俄毀滅前所備份的資料。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"내용이 많진 않지만 그가 어째서 리플레이서 킹이 되었는지 어느 정도는 추측할 수 있을 겁니다.","JPN":"内容は少ないですが、彼がなぜリプレイサー・キングになったのかについてある程度は推測できると思います。","ENG":"There's not much in there, but enough to help you piece together why he became the Replacer King.","TWN":"雖然內容不多，但應該可以大致推測出克隆·帝皇變成那樣的原因。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......고작해야 반역자의 속마음을 알려주기 위해 날 보자고 한 건가?","JPN":"……わざわざ反逆者の腹中を知らせるために私を呼び出したのか？","ENG":"So you asked to see me just so you can give me a tour inside a traitor's mind?","TWN":"……你今天約我見面就只是要告訴我叛徒的內心世界？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하하, 그럴 리가요. 그건 그냥 제 호의의 표현일 뿐입니다.","JPN":"はは、まさか。それはただ僕の好意の証なだけです。","ENG":"Hah hah, of course not. This is just a token of my friendly intent.","TWN":"哈哈，怎麼可能。那只是我表達善意的方式罷了。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그 메모리 카드에는 당신들이 본 <color=#ffd34c>테크 레벨 5</color> 장비에 대한 내용도 포함되어 있거든요.","JPN":"そのメモリーカードには、あなた方が見た<color=#ffd34c>テックレベル5</color>装備に関する内容も含まれています。","ENG":"You see, that memory card also contains information on <color=#ffd34c>Tech Level 5</color> gear you saw.","TWN":"那張記憶卡還包含你們曾看到的 <color=#ffd34c>技術等級5</color> 裝備的相關資料。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그건?!","JPN":"それは！？","ENG":"What?!","TWN":"那是？！"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마 코핀 컴퍼니의 힐데 소대장이 장착하고 나온 그 장비들을 말하는 건가?","JPN":"まさか、コフィンカンパニーのヒルデ小隊長が装着していたあの装備のことか？","ENG":"You mean the gear that the Coffin Company's Commander Hilde was wearing?","TWN":"該不會是指科芬公司希爾德隊長所持有的裝備？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그렇습니다. 스승님의 <color=#ffd34c>파프니르</color>와 <color=#ffd34c>레긴</color>만큼은 아니더라도 충분히 쓸만한 장비들을 제작할 수 있을 겁니다.","JPN":"そうです。師匠の<color=#ffd34c>レギン</color>や<color=#ffd34c>ファフニール</color>ほどではないですが、十分使えそうな装備を製作できるはずです。","ENG":"That's right. It may not be up to par with the Master's <color=#ffd34c>Fafnir</color> or <color=#ffd34c>Regin</color>, but I'm sure you can craft something plenty useful.","TWN":"是的。雖然比不上 <color=#ffd34c>帕夫尼爾</color>和 <color=#ffd34c>雷金</color>，但應該能製作出值得一用的裝備。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......역시 그 힐데 소대장도 자네와 같은 올드 카운터였나 보군.","JPN":"……やはり、あのヒルデ小隊長も君と同じオールドカウンターだったのか。","ENG":"So Hilde must have been an Old Counter like you.","TWN":"……果然你和那個希爾德隊長一樣，都是老制裁者了。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 왜 이런 걸 내게 전해주는 거지?","JPN":"ところで、なぜこんなものを私に？","ENG":"Why would you give me this though?","TWN":"但你為什麼要把這些交給我？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"호의의 표현이라고 말했을 텐데요?","JPN":"好意の証だと言ったはずです。","ENG":"Like I said, a token of our friendship.","TWN":"我應該說過，這是我表達善意的方式吧？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"헛소리 하지 말게. 이래봬도 사람 보는 눈이라면 자신 있는 편이지.","JPN":"たわ言をいうな。これでも人を見る目には自信があるからな。","ENG":"Cut the bullcrap. I've got an eye for what people are really like.","TWN":"別胡扯了。別看我這樣，我對自己看人的眼光好歹很有自信。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네 같은 자가 아무 이유 없이 이런 걸 던져줄 리가 없어.","JPN":"君みたいな者が理由もなくこれを渡すはずがない。","ENG":"Someone like you wouldn't give me this without a reason.","TWN":"你這種人不可能沒有目的地把這些東西給我。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신들은 아직 부족합니다.","JPN":"あなた方はまだまだ足りません。","ENG":"You lot still have ways to go.","TWN":"你們還不夠。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고......?","JPN":"何だと……？","ENG":"What?","TWN":"你說什麼……？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신들은 준비되지 않았어요. 그래서는 다가올 게임에서 살아남을 수 없습니다.","JPN":"あなた方は準備ができていない。それではこれからのゲームで生き残れません。","ENG":"You're not ready yet. You're not going to survive the upcoming game like that.","TWN":"你們準備得還不夠充分。這樣下去，你們無法在即將到來的遊戲中存活下去的。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"물론...... 카운터로서의 잠재력은 나쁘지 않아요.","JPN":"もちろん……カウンターとしての潜在力は悪くありません。","ENG":"Of course, your potential as Counters isn't bad.","TWN":"當然……作為制裁者的潛力還不錯。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"특히 그...... 제이크 대령인가 하는 친구는 구 관리국 시절에도 찾아보기 어려울 만한 재능을 지녔더군요.","JPN":"特にあの……ジェイク大佐なんかは旧管理局時代にも見られないほどの才能を持ってました｡","ENG":"Especially that... Colonel Jake Walker? He's so talented that he'd be a rare find even during the Old Administration.","TWN":"特別是那個……傑克上校還是誰，那位朋友的才能，即便在舊管理局時代也很難找到第二個了。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만 지금 당신들이 사용하고 있는 장비들로는...... 자신들이 가진 본래의 힘도 제대로 내기 힘들 겁니다.","JPN":"しかし、今あなた方が使っている装備では……あなた方の本来の力すら発揮できないはずです｡","ENG":"However, with the gear you use today, you'll hardly leverage your normal amount of power.","TWN":"但你們現在使用的裝備……無法發揮出你們的真正力量。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래서는...... 앞으로 나타날 더욱 강한 적들과 싸울 수 없습니다.","JPN":"今のままじゃ……これから現れるより強い敵と戦えません｡","ENG":"And like that, you won't be able to find the even more powerful enemies that will appear.","TWN":"這樣下去……你們以後無法跟更加強大的敵人戰鬥。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"당신도 그걸 알기 때문에 사설 해커들을 고용해서 관리국의 정보를 빼내려고 시도하는 거겠지요.","JPN":"あなたもそれを知ってるからこそ､私設ハッカーを雇って、管理局の情報を盗もうとしているのでしょう。","ENG":"I'm sure you realize that as well. That's why you hired private citizens to hack data from the Administration.","TWN":"妳也因為知道這一點，所以才會雇傭駭客試圖竊取管理局的資料。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"거기까지 알고 있다니 놀랍군.","JPN":"そこまで知っているなんて、驚いたな。","ENG":"I'm impressed you know that much.","TWN":"沒想到你連這個都知道，真是令人驚訝。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대체 이런 일을 하는 목적이 뭐지? 뭘 꾸미고 있는 건가?","JPN":"こんなことをする目的は何だ？　何を企んでいる。","ENG":"Why on earth are you doing this? What are you plotting here?","TWN":"你做這種事究竟有什麼目的？你在謀劃些什麼？"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"......그것만큼은 레지날드 소장과 같다고 할 수 있겠군요.","JPN":"……目的だけはレジナルド少将と同じです。","ENG":"I guess you could say I share General Reginald's purpose.","TWN":"……這一點，可以說跟雷吉納德少將差不多吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"세상을 지키기 위해서입니다.","JPN":"世界を守るためです。","ENG":"It's to protect the world.","TWN":"是為了守護世界。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그럼 이만 가 보겠습니다. 오래 머물러 봐야 소란만 생기겠죠.","JPN":"では、お先に失礼します。これ以上いても騒がしくなるだけだと思いますので。","ENG":"I'd better get going now. I'll just cause a scene if I stay any longer.","TWN":"既然事情辦完了，那我先走了。我在這裡停留太久可是會引起騷動的。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"세상을 지키기 위해서라......","JPN":"世界を守るため、か……","ENG":"Protect the world, you say...","TWN":"為了守護世界嗎……"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그건 두고 보면 알겠지.","JPN":"それは見ていればわかるだろう。","ENG":"We'll see about that.","TWN":"那我就等著瞧吧。"},"stage":{"bg":"TOMB","bgm":"THEMA_SIXWING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};